// ─── Maintenance mode check ───
// Check if maintenance file exists on claude-runner
const maintFile = require('child_process').execSync(
  'cat /home/claude-runner/gateway.maintenance 2>/dev/null || echo NONE'
).toString().trim();

if (maintFile !== 'NONE') {
  return [{ json: { valid: false, maintenanceSuppressed: true, reason: 'maintenance_active' } }];
}
// ─── End maintenance check ───

// Parse Alertmanager payload and validate it's the expected alert
const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [];

// Find PrometheusTSDBCompactionsFailing in firing state
const target = alerts.find(a =>
  a.labels?.alertname === 'PrometheusTSDBCompactionsFailing' &&
  a.status === 'firing'
);

if (!target) {
  return [{ json: { valid: false, reason: 'No firing PrometheusTSDBCompactionsFailing alert found' } }];
}

return [{ json: {
  valid: true,
  alertname: target.labels.alertname,
  namespace: target.labels?.namespace || 'monitoring',
  severity: target.labels?.severity || 'unknown',
  summary: target.annotations?.summary || target.annotations?.description || 'WAL compaction failing',
  startsAt: target.startsAt,
  instance: target.labels?.instance || 'unknown'
}}];

// 6-hour cooldown check using staticData
const COOLDOWN_MS = 6 * 60 * 60 * 1000; // 6 hours
const staticData = $getWorkflowStaticData('global');
const now = Date.now();
const lastRestart = staticData.lastRestartTime || 0;
const elapsed = now - lastRestart;
const withinCooldown = elapsed < COOLDOWN_MS;

const prev = $input.first().json;

return [{ json: {
  ...prev,
  withinCooldown,
  lastRestartTime: lastRestart,
  lastRestartAgo: lastRestart ? Math.round(elapsed / 60000) + ' min ago' : 'never',
  cooldownRemaining: withinCooldown ? Math.round((COOLDOWN_MS - elapsed) / 60000) + ' min' : '0'
}}];

// Record restart time in staticData
const staticData = $getWorkflowStaticData('global');
const now = Date.now();
staticData.lastRestartTime = now;
staticData.restartCount = (staticData.restartCount || 0) + 1;

const sshResult = $('Restart Prometheus Pod').first().json.stdout || $('Restart Prometheus Pod').first().json.stderr || '';
const deleteOk = sshResult.includes('DELETE_OK') || sshResult.includes('deleted');

const prev = $('Check Cooldown').first().json;

return [{ json: {
  ...prev,
  restartedAt: new Date(now).toISOString(),
  restartCount: staticData.restartCount,
  deleteOk,
  sshResult: sshResult.substring(0, 500)
}}];

const output = $('Check Compaction Health').first().json.stdout || '';
const recovered = output.includes('RECOVERY=OK');
const podRunning = output.includes('POD_STATUS=Running');
const prev = $('Record Restart Time').first().json;

return [{ json: {
  ...prev,
  recovered,
  podRunning,
  compactionOutput: output.substring(0, 500)
}}];

const response = $input.first().json;
const issues = Array.isArray(response) ? response : [];

if (!issues || issues.length === 0) {
  return [{ json: { action: 'no_issue_found' } }];
}

const issueId = issues[0].idReadable;
const restartCount = $('Record Restart Time').first().json.restartCount || 1;
const TOKEN = 'REDACTED_YT_TOKEN';
const BASE = 'https://youtrack.example.net/api';
const headers = { 'Authorization': 'Bearer ' + TOKEN, 'Content-Type': 'application/json' };

const commentBody = 'WAL Self-Healer: Auto-resolved.\n\nPod restarted and compaction recovered successfully (verified after 3min wait).\nTotal auto-restarts: ' + restartCount + '\n\nNo further action required.';

try {
  await fetch(BASE + '/issues/' + issueId + '/comments', { method: 'POST', headers, body: JSON.stringify({ text: commentBody }) });
} catch(e) {}

try {
  await fetch(BASE + '/commands', { method: 'POST', headers, body: JSON.stringify({ query: 'state To Verify', issues: [{ idReadable: issueId }] }) });
} catch(e) {}

return [{ json: { action: 'closed', issueId } }];

